import React, { useState, useEffect } from 'react';
import { apiFetch } from '../api';
import './css/Calendar.css';

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTH_NAMES = ['January','February','March','April','May','June','July','August','September','October','November','December'];

function startOfWeek(date) {
  const d = new Date(date);
  d.setDate(d.getDate() - d.getDay());
  d.setHours(0, 0, 0, 0);
  return d;
}

function addDays(date, n) {
  const d = new Date(date);
  d.setDate(d.getDate() + n);
  return d;
}

function formatDate(date) {
  return new Date(date).toISOString().split('T')[0];
}

function CalendarPage({ user }) {
  const [weekStart, setWeekStart] = useState(() => startOfWeek(new Date()));
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [dayMeals, setDayMeals] = useState([]);
  const [allRecipes, setAllRecipes] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [draggingOver, setDraggingOver] = useState(false);

  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(weekStart, i));

  // Fetch user's recipes once
  useEffect(() => {
    if (!user) return;
    apiFetch(`/recipes/user/${user.id || user._id}`)
      .then(r => r.ok ? r.json() : [])
      .then(setAllRecipes)
      .catch(() => {});
  }, [user]);

  // Fetch meals for selected date
  useEffect(() => {
    if (!user) return;
    const date = formatDate(selectedDate);
    apiFetch(`/mealPlans/${date}/${user.id || user._id}`)
      .then(r => r.ok ? r.json() : [])
      .then(async (plans) => {
        const recipes = await Promise.all(
          plans.map(p =>
            apiFetch(`/recipes/${p.recipe_id}`)
              .then(r => r.ok ? r.json() : null)
              .then(recipe => recipe ? { ...recipe, mealPlanId: p._id } : null)
          )
        );
        setDayMeals(recipes.filter(Boolean));
      })
      .catch(() => setDayMeals([]));
  }, [selectedDate, user]);

  const handleDrop = async (e) => {
    e.preventDefault();
    setDraggingOver(false);
    const recipe = JSON.parse(e.dataTransfer.getData('recipe'));
    const date = formatDate(selectedDate);
    try {
      const r = await apiFetch(
        `/mealPlans/Create/${date}/${user.id || user._id}/${recipe._id}`,
        { method: 'POST', body: JSON.stringify({}) }
      );
      if (r.ok) {
        const plan = await r.json();
        setDayMeals(prev => [...prev, { ...recipe, mealPlanId: plan._id }]);
      }
    } catch (err) {}
  };

  const removeMeal = async (mealPlanId) => {
    try {
      const r = await apiFetch(`/mealPlans/Delete/${mealPlanId}`, { method: 'DELETE' });
      if (r.ok) setDayMeals(prev => prev.filter(m => m.mealPlanId !== mealPlanId));
    } catch (err) {}
  };

  const filteredRecipes = allRecipes.filter(r =>
    r.recipe_name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const today = new Date();
  today.setHours(0, 0, 0, 0);

  const selectedLabel = (() => {
    const d = new Date(selectedDate);
    d.setHours(0, 0, 0, 0);
    const diff = Math.round((d - today) / 86400000);
    if (diff === 0) return 'Today';
    if (diff === 1) return 'Tomorrow';
    if (diff === -1) return 'Yesterday';
    return `${DAY_NAMES[d.getDay()]}, ${MONTH_NAMES[d.getMonth()]} ${d.getDate()}`;
  })();

  const weekLabel = (() => {
    const end = addDays(weekStart, 6);
    const startM = MONTH_NAMES[weekStart.getMonth()].slice(0, 3);
    const endM = MONTH_NAMES[end.getMonth()].slice(0, 3);
    return `${startM} ${weekStart.getDate()} – ${startM !== endM ? endM + ' ' : ''}${end.getDate()}`;
  })();

  return (
    <div className="planner-page">
      {/* Week navigation */}
      <div className="planner-header">
        <h1>Planner</h1>
        <div className="week-nav">
          <button className="week-nav-btn" onClick={() => { setWeekStart(addDays(weekStart, -7)); }}>←</button>
          <span className="week-label">{weekLabel}</span>
          <button className="week-nav-btn" onClick={() => { setWeekStart(addDays(weekStart, 7)); }}>→</button>
        </div>
      </div>

      {/* Week strip */}
      <div className="week-strip">
        {weekDays.map((day, i) => {
          const d = new Date(day);
          d.setHours(0, 0, 0, 0);
          const isSelected = formatDate(d) === formatDate(selectedDate);
          const isToday = formatDate(d) === formatDate(today);
          return (
            <button
              key={i}
              className={`week-day${isSelected ? ' week-day--selected' : ''}${isToday ? ' week-day--today' : ''}`}
              onClick={() => setSelectedDate(new Date(day))}
            >
              <span className="week-day-name">{DAY_NAMES[d.getDay()]}</span>
              <span className="week-day-num">{d.getDate()}</span>
            </button>
          );
        })}
      </div>

      <div className="planner-body">
        {/* Drop zone */}
        <div className="planner-section">
          <div className="planner-section-header">
            <h2>{selectedLabel}</h2>
            {dayMeals.length > 0 && (
              <span className="meal-count">{dayMeals.length} meal{dayMeals.length !== 1 ? 's' : ''}</span>
            )}
          </div>

          <div
            className={`drop-zone${draggingOver ? ' drop-zone--over' : ''}${dayMeals.length === 0 ? ' drop-zone--empty' : ''}`}
            onDragOver={(e) => { e.preventDefault(); setDraggingOver(true); }}
            onDragLeave={() => setDraggingOver(false)}
            onDrop={handleDrop}
          >
            {dayMeals.length === 0 ? (
              <div className="drop-zone-hint">
                <span className="drop-zone-icon">🍽</span>
                <span>Drag a recipe here to plan your meal</span>
              </div>
            ) : (
              <div className="meal-list">
                {dayMeals.map((meal, i) => (
                  <div key={i} className="meal-item">
                    {meal.image_url && (
                      <img src={meal.image_url} alt={meal.recipe_name} className="meal-item-img" />
                    )}
                    <div className="meal-item-info">
                      <span className="meal-item-name">{meal.recipe_name}</span>
                      {meal.cuisine && <span className="meal-item-cuisine">{meal.cuisine}</span>}
                    </div>
                    <button className="meal-item-remove" onClick={() => removeMeal(meal.mealPlanId)}>✕</button>
                  </div>
                ))}
                <div className="drop-zone-add-hint">+ Drop another recipe</div>
              </div>
            )}
          </div>
        </div>

        {/* Recipe picker */}
        <div className="planner-section">
          <div className="planner-section-header">
            <h2>Your Recipes</h2>
            <input
              type="search"
              placeholder="Search..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="planner-search"
            />
          </div>

          <div className="recipe-picker">
            {filteredRecipes.length === 0 ? (
              <p className="picker-empty">No recipes found.</p>
            ) : (
              filteredRecipes.map((recipe, i) => (
                <div
                  key={i}
                  className="picker-card"
                  draggable
                  onDragStart={e => e.dataTransfer.setData('recipe', JSON.stringify(recipe))}
                  title="Drag to add to your plan"
                >
                  <div className="picker-card-img">
                    {recipe.image_url
                      ? <img src={recipe.image_url} alt={recipe.recipe_name} />
                      : <span>🍽</span>
                    }
                    <div className="picker-card-drag-hint">drag</div>
                  </div>
                  <div className="picker-card-name">{recipe.recipe_name}</div>
                  {recipe.cuisine && <div className="picker-card-cuisine">{recipe.cuisine}</div>}
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default CalendarPage;
